    pub fn from_csv(csv_content: &str) -> Result<Self, crate::error::Error>;

    /// Get ship by name (case-insensitive)
    pub fn get(&self, name: &str) -> Option<&ShipAttributes>;

    /// List all available ship names
    pub fn ship_names(&self) -> Vec<&str>;
}
