                })
                .collect()
        })
        .unwrap_or_default();

    let response = ScoutGatesResponse {
        system: request.system.clone(),
        system_id,
        count: neighbors.len(),
        neighbors,
    };

    // Record business metrics
    record_systems_queried("gates", "scout-gates");
    record_neighbors_returned(response.count, "gates");

    info!(
        request_id = %request_id,
        system = %request.system,
        neighbors = response.count,
        "scout gates completed"
    );

    Response::Success(ServiceResponse::new(response))
}

