            max_jump: None,
            avoid: vec![],
            avoid_gates: false,
            max_temperature: None,
        };
        let err = req.validate("test").unwrap_err();
        assert!(err.detail.as_deref().unwrap().contains("'from'"));
    }

    #[test]
    fn test_route_request_empty_to() {
        let req = RouteRequest {
            from: "Nod".to_string(),
            to: "   ".to_string(),
            algorithm: RouteAlgorithm::Bfs,
