        };
        let err = req.validate("test").unwrap_err();
        assert!(err.detail.as_deref().unwrap().contains("'to'"));
    }

    #[test]
    fn test_route_request_negative_max_jump() {
        let req = RouteRequest {
            from: "Nod".to_string(),
            to: "Brana".to_string(),
